<template><el-card><template #header><div class="head"><b>{{expiring?'居住证即将到期':'居住证管理'}}</b><el-button v-if="!expiring&&user.hasPermission('residence-permit:apply')" type="primary" @click="$router.push('/residence-permits/applications/first-issue')">首次申领</el-button></div></template><el-table :data="rows"><el-table-column prop="permitNo" label="证件号"/><el-table-column prop="personName" label="姓名"/><el-table-column prop="maskedIdentityNo" label="身份证号"/><el-table-column prop="currentAddress" label="居住地址"/><el-table-column prop="validUntil" label="有效期至"/><el-table-column v-if="expiring" prop="remainingDays" label="剩余天数"/><el-table-column prop="status" label="状态"/><el-table-column label="操作"><template #default="{row}"><el-button link @click="$router.push('/residence-permits/'+row.permitId)">详情</el-button></template></el-table-column></el-table></el-card></template>
<script setup>import{ref,onMounted}from'vue';import{useRoute}from'vue-router';import{useUserStore}from'../../stores/user';import{getPermits,getExpiring}from'../../api/floatingResidence';const route=useRoute(),user=useUserStore(),expiring=route.meta.expiring,rows=ref([]);onMounted(async()=>{const r=expiring?await getExpiring():await getPermits({page:0,size:50});rows.value=Array.isArray(r)?r:(r.content||[])})</script><style scoped>.head{display:flex;justify-content:space-between}</style>
